descriptor.templateCss:
.sync-container { padding: 20px; background: #0d1b2a; border-radius: 12px; color: #fff; height: 100%; display: flex; flex-direction: column; font-family: 'Inter', sans-serif; border: 1px solid rgba(255,255,255,0.1); }
.sync-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 15px; }
.sync-stats { display: flex; gap: 15px; }
.stat-item { background: rgba(255,255,255,0.05); padding: 5px 15px; border-radius: 6px; }
.stat-item.out-of-sync { background: rgba(244, 67, 54, 0.15); color: #f44336; border: 1px solid rgba(244,67,54,0.3); }
.sync-filters { display: flex; gap: 10px; }
.filter-btn { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: #fff; padding: 6px 12px; border-radius: 4px; cursor: pointer; }
.filter-btn.active { background: #1b263b; border-color: #415a77; }
.table-wrapper { flex: 1; overflow-y: auto; }
.sync-table { width: 100%; border-collapse: collapse; }
.sync-table th { padding: 12px; font-size: 11px; color: #778da9; text-align: left; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid rgba(255,255,255,0.1); }
.sync-table td { padding: 12px; border-bottom: 1px solid rgba(255,255,255,0.05); font-size: 13px; }
.status-badge { padding: 3px 10px; border-radius: 12px; font-size: 10px; font-weight: 800; }
.status-badge.in-sync { background: rgba(76, 175, 80, 0.2); color: #4caf50; }
.status-badge.out-of-sync { background: rgba(244, 67, 54, 0.2); color: #f44336; animation: pulse 2s infinite; }
@keyframes pulse { 0% { opacity: 1; } 50% { opacity: 0.6; } 100% { opacity: 1; } }
.val-box { background: rgba(255,255,255,0.05); padding: 2px 8px; border-radius: 4px; min-width: 40px; display: inline-block; text-align: center; border: 1px solid rgba(255,255,255,0.1); }
.go-btn { background: #415a77; border: none; color: #fff; padding: 6px 12px; border-radius: 4px; cursor: pointer; font-size: 11px; font-weight: 600; }

descriptor.controllerScript:
self.onInit = function() {
    var $container = $(self.ctx.$container);
    self.ctx.state = { filterOutOfSync: false };

    self.ctx.updateSyncTable = function() {
        var data = self.ctx.data;
        if (!data) return;
        var entities = {};

        data.forEach(function(ds) {
            var entityName = ds.datasource.entityName;
            if (!entities[entityName]) {
                entities[entityName] = { name: entityName, id: ds.datasource.entityId, lastSeen: 0, desiredHvac: '---', reportedHvac: '---', desiredDimmer: '---', reportedDimmer: '---', status: 'IN_SYNC' };
            }
            var key = ds.dataKey.name.toLowerCase();
            var val = (ds.data && ds.data.length) ? ds.data[ds.data.length - 1][1] : null;
            var ts = (ds.data && ds.data.length) ? ds.data[ds.data.length - 1][0] : 0;

            if (val !== null && val !== undefined) {
                if (key.includes('hvac_command')) entities[entityName].desiredHvac = val;
                else if (key.includes('reported_hvac') || key.includes('hvac_mode') || key.includes('hvac_reported')) entities[entityName].reportedHvac = val;
                else if (key.includes('dimmer_command')) entities[entityName].desiredDimmer = val;
                else if (key.includes('reported_dimmer') || key.includes('dimmer_reported') || key.includes('lighting_dimmer')) entities[entityName].reportedDimmer = val;
                else if (key.includes('sync_status')) entities[entityName].status = val;
                if (ts > entities[entityName].lastSeen) entities[entityName].lastSeen = ts;
            }
        });

        var rows = Object.values(entities);
        var $body = $('#syncTableBody', $container); $body.empty();
        var total = 0; var outCount = 0;

        rows.forEach(function(e) {
            total++;
            var isOut = (String(e.status).toUpperCase() === 'OUT_OF_SYNC');
            if (isOut) outCount++;
            if (self.ctx.state.filterOutOfSync && !isOut) return;

            var row = $('<tr>');
            row.append($('<td>').text(e.name));
            row.append($('<td>').text(e.lastSeen ? new Date(e.lastSeen).toLocaleTimeString() : '---'));
            row.append($('<td>').html('<span class="val-box">' + e.desiredHvac + '</span>'));
            row.append($('<td>').html('<span class="val-box">' + e.reportedHvac + '</span>'));
            row.append($('<td>').html('<span class="val-box">' + e.desiredDimmer + (e.desiredDimmer === '---' ? '' : '%') + '</span>'));
            row.append($('<td>').html('<span class="val-box">' + e.reportedDimmer + (e.reportedDimmer === '---' ? '' : '%') + '</span>'));
            row.append($('<td>').html('<span class="status-badge ' + (isOut ? 'out-of-sync' : 'in-sync') + '">' + (isOut ? 'OUT_OF_SYNC' : 'IN_SYNC') + '</span>'));
            row.append($('<td>').append($('<button class="go-btn">View Room</button>').click(function() {
                self.ctx.stateController.updateState('room_control', { entityId: e.id, entityName: e.name }, false);
            })));
            $body.append(row);
        });

        $('#totalCount', $container).text(total); $('#outOfSyncCount', $container).text(outCount);
    };

    $('#btnAll', $container).click(function() { $('.filter-btn', $container).removeClass('active'); $(this).addClass('active'); self.ctx.state.filterOutOfSync = false; self.ctx.updateSyncTable(); });
    $('#btnOutOfSync', $container).click(function() { $('.filter-btn', $container).removeClass('active'); $(this).addClass('active'); self.ctx.state.filterOutOfSync = true; self.ctx.updateSyncTable(); });
};
self.onDataUpdated = function() { self.ctx.updateSyncTable(); };
